import './index.css';

import Navbar from
'../../components/common/Navbar';

import Sidebar from
'../../components/common/Sidebar';

function TeacherDashboard() {

  return (

    <div className="dashboard">

      <Sidebar />

      <div className="dashboard-content">

        <Navbar />

        <div className="cards">

          <div className="card">
            Students
          </div>

          <div className="card">
            Subjects
          </div>

          <div className="card">
            Analytics
          </div>

        </div>

      </div>

    </div>

  );

}

export default TeacherDashboard;
